import React, { useState, useEffect } from "react";
import { Routes, Route } from "react-router-dom";

import Navbar from "./components/layout/Navbar";
import HomePage from "./pages/HomePage";
import IssuerPortal from "./pages/IssuerPortal";
import VerifierPortal from "./pages/VerifierPortal";
import StudentPortal from "./pages/StudentPortal";

function App() {
  const [theme, setTheme] = useState("light");

  useEffect(() => {
    const stored = window.localStorage.getItem("cert-theme");
    if (stored === "light" || stored === "dark") {
      setTheme(stored);
    }
  }, []);

  const toggleTheme = () => {
    setTheme((prev) => {
      const next = prev === "dark" ? "light" : "dark";
      window.localStorage.setItem("cert-theme", next);
      return next;
    });
  };

  return (
    <div className={`app-root ${theme}`}>
      <Navbar theme={theme} toggleTheme={toggleTheme} />
      <main className="app-main">
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/issuer" element={<IssuerPortal />} />
          <Route path="/verify" element={<VerifierPortal />} />
          <Route path="/student" element={<StudentPortal />} />
        </Routes>
      </main>
    </div>
  );
}

export default App;
